let modalInstance = null;

function showModal(title, message, callback) {
  const modal = document.getElementById('customModal');

  if (!modal) {
    console.error('Modal element not found.');
    return;
  }

  // Update modal content
  const titleElement = document.getElementById('exampleModalLabel');
  const messageElement = document.querySelector('.modal-body p');

  if (titleElement && messageElement) {
    titleElement.textContent = title;
    messageElement.textContent = message;
  }

  // Show the modal
  if (modalInstance) {
    modalInstance.hide();
  }

  modalInstance = new bootstrap.Modal(modal);
  modalInstance.show();

  // Optional: Run callback after modal is closed
  modalInstance._element.addEventListener('hidden.bs.modal', () => {
    if (callback) callback();
  });
}
```

---

### ✅ Usage Example

