use gtk::prelude::*;
use gtk::{Application, ApplicationWindow, DrawingArea};
use gdk::prelude::*;
use gdk::{PixelBuffer, SurfaceType};
use cairo::{Context, ImageSurface};

fn main() {
    // Initialize the GTK application
    let app = Application::new("com.example.pixelbuffer", Default::default())
        .expect("Application initialization failed");

    app.connect_activate(|app| {
        // Create a window
        let window = ApplicationWindow::new(app);
        window.set_title("PixelBuffer Example");
        window.set_default_size(640, 480);

        // Create a drawing area
        let drawing_area = DrawingArea::new();
        drawing_area.set_size_request(640, 480);
        window.add(&drawing_area);

        // Create a PixelBuffer
        let pixel_buffer = PixelBuffer::new(SurfaceType::Rgb24, 640, 480)
            .expect("Failed to create PixelBuffer");

        // Create a Cairo context on the PixelBuffer
        let surface = ImageSurface::create_from_pixel_buffer(&pixel_buffer).unwrap();
        let mut context = Context::new(&surface);

        // Draw a red rectangle
        context.set_source_rgb(1.0, 0.0, 0.0); // Red
        context.rectangle(0.0, 0.0, 640.0, 480.0);
        context.fill().unwrap();

        // Render the PixelBuffer to the drawing area
        drawing_area.connect_draw(move |_, cr| {
            // Create a Cairo context on the drawing area
            let surface = ImageSurface::create_rgb(cairo::Format::Rgb24, 640, 480);
            let mut context = Context::new(&surface);

            // Draw the PixelBuffer to the surface
            context.set_source_surface(&surface, 0.0, 0.0);
            context.paint();

            // Draw to the drawing area's Cairo context
            cr.set_source_surface(&surface, 0.0, 0.0);
            cr.paint();

            Inhibit(false)
        });

        // Show all widgets
        window.show_all();
    });

    // Run the application
    app.run();
}
```

