      try {
        const response = await fetch(url);
        const data = await response.json();

        // Get precipitation probability from the first hour of the day
        const precipitationProbability = data.hourly.precipitation_probability[0];

        // Determine if precipitation is likely
        const isLikely = precipitationProbability > 50;

        return { isLikely, precipitationProbability };
      } catch (error) {
        console.error("Error fetching weather data:", error);
        throw error;
      }
    }

    // Main function to run the whole process
    async function main() {
      try {
        const { latitude, longitude } = await getUserLocation();
        console.log("User Location:", latitude, longitude);

        const { isLikely } = await fetchWeatherData(latitude, longitude);
        console.log("Precipitation Likely:", isLikely);

        // Change background color based on precipitation likelihood
        document.body.style.backgroundColor = isLikely ? "blue" : "green";
      } catch (error) {
        console.error("Error:", error);
        document.body.style.backgroundColor = "red";
        document.body.innerHTML = `<h1>Error: ${error}</h1>`;
      }
    }

    // Run the main function
    main();
  </script>
</body>
