    "spectator": {
      "matches": ["read"],
      "teams": ["read"],
      "stats": ["read"]
    }
  }
}
```

Then, in JavaScript:

```javascript
function canUserDoAction(userRole, action, resource) {
  const role = rolePermissions.roles[userRole];
  if (!role || !role[resource]) return false;

  return role[resource].includes(action);
}
```

